sp_widget.client_script:
api.controller=function ($scope, nowAttachmentHandler, $rootScope,amb, spUtil, spModal, $log, spAriaUtil) {
	var c = this;
	$scope._attachmentCount = undefined;
	$scope.errorMessages = [];
	$scope.attachmentHandler = new nowAttachmentHandler(setAttachments, appendError);
	$scope.data.action = "";
	function resetAttachments(){
			// reset the attachment handler
			$scope.attachmentHandler.setParams(c.data.table, c.data.sys_id, 1024 * 1024 * $scope.data.maxAttachmentSize);
			$scope.attachmentHandler.getAttachmentList();
	}

	// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
	var watcher;
	initRecordWatcher(c.data.table, "table_sys_id=" + c.data.sys_id);
	function initRecordWatcher(table, filter) {
		if (watcher)
			watcher.unsubscribe();

		if (table && filter) {
			// STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
			var params = {};
			var watcherChannel = amb.getChannelRW(table, filter);
			amb.connect();
			watcher = watcherChannel.subscribe(function(name) {
				$scope.server.update();
			});
		}
	}

	$rootScope.$on('$TaskerTaskList.click', function(e, parms) {
		// only process this event when the table's are equivalent
		if(c.data.table == parms.table && c.data.sys_id != parms.sys_id){
			c.data.sys_id = parms.sys_id;
			$scope.server.update().then(function(){
				// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
				resetAttachments();
				initRecordWatcher(c.data.table, "table_sys_id=" + c.data.sys_id);
			});
		}
	});

	$rootScope.$on('$sp.list.click', function(e, parms) {
		// only process this event when the table's are equivalent
		if(c.data.table == parms.table && c.data.sys_id != parms.sys_id){
			c.data.sys_id = parms.sys_id;
			$scope.server.update().then(function(){
				// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
				resetAttachments();
				initRecordWatcher(c.data.table, "table_sys_id=" + c.data.sys_id);
			});
		}
	});
	$rootScope.$on('$taskerTabbedForm.drillDownList.click', function(e, parms) {
		// only process this event when the table's are equivalent
		if(c.data.table == parms.table && c.data.sys_id != parms.sys_id){
			c.data.sys_id = parms.sys_id;
			$scope.server.update().then(function(){
				// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
				resetAttachments();
				initRecordWatcher(c.data.table, "table_sys_id=" + c.data.sys_id);
			});
		}
	});

	$scope.$evalAsync(function() {
		$scope.attachmentHandler.setParams($scope.data.table, $scope.data.sys_id, 1024 * 1024 * $scope.data.maxAttachmentSize);
		$scope.attachmentHandler.getAttachmentList();
	});

	$scope.hasAttachments = function() {
		// RJ | STRY0059145 | Include Attachments since we dropped attachment properties
		$scope.attachmentCount();
		return $scope.attachments && $scope.attachments.length != 0;
	};

	// RJ | STRY0059145 | Include Attachments since we dropped attachment properties
	$scope.attachmentCount = function() {
		var attachmentCount;
		if($scope.attachments){
			attachmentCount = $scope.attachments.length;	
		}
		else{
			attachmentCount = '';
		}
		// only broadcast if the value changes
		if($scope._attachmentCount!=attachmentCount){
			$rootScope.$broadcast("tasker_task_attachments.count", {
				count: attachmentCount,
				source: $scope.data.widgetname				
			});
			$scope._attachmentCount=attachmentCount;
		}
		return attachmentCount;
	};

	$scope.canWrite = function() {
		return $scope.data.canWrite;
	};

	$scope.confirmDeleteAttachment = function(attachment) {
		spModal.confirm("${Delete Attachment?}").then(function() {
			$scope.attachmentHandler.deleteAttachment(attachment);
		});
	};

	$scope.$on('dialog.upload_too_large.show', function(e){
		$log.error($scope.data.largeAttachmentMsg);
		spUtil.addErrorMessage($scope.data.largeAttachmentMsg);
	});

	$scope.$on('added_attachment', function(evt) {
		$scope.data.action = "added";
		spUtil.update($scope);
	});

	$scope.$on('sp.record.can_write', function(evt, answer) {
		$scope.data.canWrite = answer;
	});

	function appendError(error) {
		$scope.errorMessages.push(error);
		spUtil.addErrorMessage(error.msg + error.fileName);
	}

	function setAttachments(attachments, action) {
		if ($scope.submitting == true)
			return;

		$scope.attachments = attachments;
		if (!action)
			return;

		if (action === "added") {
			spAriaUtil.sendLiveMessage($scope.data.attachmentSuccessMsg);
		}

		$scope.data.action = action;
		spUtil.update($scope);
	}
};

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.03.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------
// No updates needed on Tasker theme

/* Patch 1 DFCT0010866; Link adds this CSS selector to flex now attachments list part 1 */
.dtech-flex-col-grow-oflow-hid-posrel {
  display: flex;
  flex-flow: column nowrap;
  flex-grow: 1;
  overflow: hidden;
  position: relative;
}

/* Patch 1 DFCT0010866; Link adds this CSS selector to flex now attachments list part 2 */
.dtech-oflow-auto-pad-r-5-posabso {
  bottom: 0;
  margin-bottom: 0;
  overflow: auto;
  padding-left: 0;
  padding-right: 5px;
  position: absolute;
  scrollbar-gutter: stable;
  top: 0;
  width: -webkit-fill-available;
}

sp_widget.link:
function link(scope, element, attrs, controller) {	
	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer
	// This function gets called from the Client controller and adds CSS to the ServiceNow directive of
	// tag <now-attachments-list> to allow it to flex and have a scrollbar when bifold == true
	scope.linkFlexAttachments = function() {
		if (scope.data.bifold) {
			// Tabs for Attachments use directive now attachments list which we get by a ClassName then add a class to all occurrences
			angular.element(document.getElementsByClassName('file-list-wrap'))
			.addClass('dtech-flex-col-grow-oflow-hid-posrel');

			angular.element(document.getElementsByClassName('list-group'))
			.addClass('dtech-oflow-auto-pad-r-5-posabso');
		}
	};

}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CREATED BY: AYMAN A.
// WIDGET BASE: Attachments
// LAST UPDATE: 08.26.20
//------------------------------------------------------------------------------------------------------------------------
// 2.7.0 | 2021-11-18 | raj  | STRY0114416 - 4 - 2.7 Certification Fixes
//                                         Changes made in Server Script
// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
//                                      In HTML, wrap attachment list in a <div> and if isModal true use scrollbar
//                                      In CSS, add block for scrollbar selectors
//                                      In Server script, get isModal from input/options/false
//                                      In Client controller, change to api.controller=function.
//                                      Changes made in HTML, CSS, Server script and Client controller
// 2.8 | 2022-08-06 | mmcc | DFCT0010866 - Too many scroll bars are displaying  on the split view on Document Management, and Delegation View
//                                      In HTML, use ngclass to add flex css when bifold.
//                                      In CSS, removed .padder-b-none
//                                      In Server script, added bifold load and convertToBool()
//                                      In Client controller, calling linkFlexAttachments()
//                                      Add code in Link to update CSS for Attachments directive
//                                      Changes made in HTML, CSS, Server script, Client controller and Link.
// 2.8 | 2022-08-07 | mmcc | Patch 1 DFCT0010866 - Too many scroll bars are displaying  on the split view on Document Management, and Delegation View
//                                      In HTML, add a call to getOuterDivCssByBifold()
//                                      In CSS, added 2 CSS selectors that Link can use AddClass() to flex and scroll Attachments
//                                      In Client controller, in hasAttachments() remove call to linkFlexAttachments(); add getOuterDivCssByBifold()
//                                      In Link, updated linkFlexAttachments() to add a class to all occurrences
//                                      Changes made in HTML, CSS, Client controller and Link.
// 2.8 | 2022-08-08 | mmcc | Patch 2 DFCT0010866 - Too many scroll bars are displaying  on the split view on Document Management, and Delegation View
//                                      In Client controller, in getOuterDivCssByBifold() use isModal
//                                      Changes made in Client controller.
// 2.8 | 2022-08-25 | mmcc | DFCT0011206 - DocIntegrator needs to flex when used in the Tasker App
//                                      In HTML, added OR isModal to a few ngclass's; changed panel-body to flex 1 1 0; removed getOuterDivCssByBifold()
//                                      In CSS, removed .dtech-modal-scroll-height-attachments
//                                      In Client controller, delete getOuterDivCssByBifold()
//                                      Changes made in HTML, CSS and Client controller.
// 2.8 | 2022-08-31 | raj  | DFCT0011162 - "Document Management": view should NOT hide the tabs "Shared Attachment", & "My Attachments' when uploading files in the My Attachment tab
//																			Changes in the client script to reload widgets differently so the widget always exits and just changes instead of being set to null and readded
// 2.8 | 2022-08-31 | raj  |  DFCT0011236 - Click on any banner notification > My Task > Awaiting Acceptance, click "My Attachments", 'tab', that should NOT go away other tabs
//																			Changes in the client script to reload widgets differently so the widget always exits and just changes instead of being set to null and readded
// 2.8 | 2022-09-06 | raj  | DFCT0011217 - Stretch - "My Attachments' should be ONLY allowed to the associated  Task to the Task owner when uploading files in the My Attachment tab
//																			In Server Script - pass canAttach to related list builder
//
//------------------------------------------------------------------------------------------------------------------------
(function($sp, input, data, options, gs) {
	// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists; added isModal
	data.isModal = (input || {}).isModal || (options || {}).isModal || false;

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; added bifold
	data.bifold = (input || {}).bifold || (options || {}).bifold || false;

	//2.5.21: 08.26.20 | DTLV | KT | Set up Title
	data.title = options.title || gs.getMessage("Attachments");
	//data.icon = options.icon;
	//STRY0059145 | Include Attachments since we dropped attachment properties
	data.sys_id = (input || {}).sys_id || options.record_id || $sp.getParameter("sys_id");
	data.table = (input || {}).table || options.record_table || $sp.getParameter("table");
	data.widgetname = (input || {}).name || options.record_name || $sp.getParameter("widget_name");
	data.table = _getActualTable(data.table, data.sys_id);
	data.maxAttachmentSize = parseInt(gs.getProperty("com.glide.attachment.max_size", 1024));
	if (isNaN(data.maxAttachmentSize))
		data.maxAttachmentSize = 24;
	data.largeAttachmentMsg = gs.getMessage("Attached files must be smaller than {0} - please try again", "" + data.maxAttachmentSize + "MB");
	data.attachmentSuccessMsg = gs.getMessage("Attachment successfully uploaded");  
	data.SNAttachmentsON = 'true'; //KT | STRY0072011 | 2.5.13 | Added: & data.SNAttachmentsON == true && data.isActive == true;
	data.isActive = false; //KT | STRY0072011 | 2.5.13 | Added: & data.SNAttachmentsON == true && data.isActive == true;

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; added convertToBool() call
	convertToBool(['bifold', 'isModal']);

	if (!data.table || !data.sys_id)
		return;

	// DFCT0011217 - change glide record name to set the gr_Task_Attachments record for the task.
	//               this is helpful to get the task for shared attachements when the id and table are the tree
	var gr_Task_Attachments;

	// STRY0114416  NOTE: using glide record here b/c we are setting permissions in this script
	var gr_Table_of_Attachments = new GlideRecord(data.table);
	if (!gr_Table_of_Attachments.isValid())
		return;

	if (!gr_Table_of_Attachments.get(data.sys_id))
		return;

	if (input && input.action == "deleted") {
		gr_Table_of_Attachments.comments = input.action + " an attachment";
		gr_Table_of_Attachments.update();
	}
	if(input){
		data.sys_id = input.sys_id;
	}

	// DFCT0011217 - set default values for all tables, this may be overriden for Task and Task Tree
	data.isActive = gr_Table_of_Attachments.active;
	data.canRead = gr_Table_of_Attachments.canRead();
	data.canWrite = gr_Table_of_Attachments.canWrite();
	data.canAttach = data.canWrite && gs.hasRole(gs.getProperty("glide.attachment.role"));

	//STRY0072011 | 2.5.13
	if (data.table == 'x_153465_discovert_route_task_instance' ||
			data.table == 'x_153465_discovert_task_tree'){
		// NOTE: using glide record here b/c we are setting permissions in this script
		gr_Task_Attachments = new GlideRecordSecure('x_153465_discovert_route_task_instance');
		data.task_id = (input || {}).task_id || options.task_id || $sp.getParameter("task_id");
		if(gr_Task_Attachments.get(data.task_id)){
			//------------------------------------------------------------------------------------------------------------------------
			// CUSTOM: DOC. INT INTEGRATION - INITIALIZING VARIABLES 
			//------------------------------------------------------------------------------------------------------------------------
			var tDS = new taskerDocumentScripts();
			var currentAttachDocSettings = tDS.getAttachmentAndDocumentSettings(gr_Task_Attachments);
			data.SNAttachmentsON = currentAttachDocSettings.sNOWAttachmentsOn.toString();
			//------------------------------------------------------------------------------------------------------------------------
			var TaskACLs = new TaskerTaskACLs(gr_Task_Attachments);
			var canAttach = TaskACLs.canAttach();
			data.canWrite = canAttach && data.SNAttachmentsON == 'true'; //STRY0072011 | 2.5.13 | Added: & data.SNAttachmentsON == true && data.isActive == true;
			// DFCT0011217
			data.canAttach = data.canWrite && gs.hasRole(gs.getProperty("glide.attachment.role"));
		} else {
			data.canWrite = false;
			data.canAttach = false;
			data.canRead = false;
		}
	}


	function _getActualTable(table, id) {
		if (!table)
			return table;

		var rec = new GlideRecord(table);
		if (!rec.isValid())
			return table;

		if (rec.get(id) && rec.getValue('sys_class_name')) {
			return rec.getValue('sys_class_name');
		}
		return table;
	}

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; added function convertToBool()
	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}

})($sp, input, data, options, gs);
